from agent import *from models.products import *import simplejsonX_URLS = ['https://keyboardkings.com/secret-lab-omega-vs-titan/', 'https://keyboardkings.com/planck-ez-vs-olkb-planck-vs-preonic/', 'https://keyboardkings.com/dxracer-vs-gtracing-vs-maxnomic-vs-secretlab/', 'https://keyboardkings.com/keyboards-without-number-pads-a-complete-guide/']def run(context, session):    session.queue(Request("https://keyboardkings.com/category/resources/keyboard-reviews/", use='curl'), process_category, dict(cat='Keyboards'))    session.queue(Request("https://keyboardkings.com/category/resources/chair-reviews/", use='curl'), process_category, dict(cat='Chairs'))    session.queue(Request("https://keyboardkings.com/category/resources/keyboard-mice-reviews/", use='curl'), process_category, dict(cat='Mice'))def process_category(data, context, session):    revs = data.xpath('//div[@class="button-container"]/a')    for rev in revs:        url = rev.xpath('@href').string()        session.queue(Request(url, use='curl'), process_review, dict(context, url=url))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url, use='curl'), process_category, dict(context))def process_review(data, context, session):    prods = data.xpath('//ol/li/strong')    prods_2 = data.xpath('//hr[@class="wp-block-separator is-style-wide"]/preceding-sibling::h3[1]')    if prods or len(prods_2) > 1 and 'How do I sync my Microsoft wireless' not in data.xpath('//hr[@class="wp-block-separator is-style-wide"]/preceding-sibling::h3[1]//text()').string() or context['url'] in X_URLS:        if context['url'] != 'https://keyboardkings.com/gmmk-glorious-modular-mechanical-keyboard-build-and-review/':            process_reviews(data, context, session)            return    product =  Product()    product.category = context['cat']    product.url = data.xpath('//a[@rel="noreferrer noopener nofollow"]/@href').string()    if not product.url:        product.url = data.xpath('//a[@rel="noopener noreferrer"]/@href').string()    if not product.url:        product.url = context['url']    product.url = product.url.split('ref=')[0].split('?')[0]    product.name = data.xpath('//a[@class="ez-toc-link ez-toc-heading-1"]/text()').string()    if not product.name:        product.name = data.xpath('(//h2)[position() = 1]//text()').string()    if "What" in product.name:        product.name = data.xpath('//h1[@class="entry-title"]//text()').string().split(' Review')[0].split(' Build')[0]    product.ssid = product.name.lower().replace(' ', '-')    review = Review()    review.type = 'pro'    review.title = data.xpath('//h1[@class="entry-title"]//text()').string(multiple=True)    review.ssid = product.ssid    review.url = context['url']    review.date = data.xpath('//meta[@property="article:published_time"]/@content').string().split('T')[0]        conclusion = ""    replace_content = ""    conclusion_content = data.xpath('//h2/span[@id="Conclusion"]/parent::*/following-sibling::p')    if not conclusion_content:        conclusion_content = data.xpath('//h2/span[@id="Wrapping_Up"]/parent::*/following-sibling::p')    for content in conclusion_content:        if content.xpath('strong/em') or 'Interested? Check it out' in content.xpath('.//text()').string(multiple=True) or 'You may also be interested in' in content.xpath('.//text()').string(multiple=True):            replace_content += content.xpath('.//text()').string(multiple=True)            break        conclusion += content.xpath('.//text()').string(multiple=True).strip().replace('. ', '.').replace('.', '. ')    if conclusion != "":        review.add_property(type='conclusion', value=conclusion)    pros_cons = data.xpath('//h2/span[@id="Pros_and_Cons"]/parent::*/following-sibling::table/tbody/tr/td')    if not pros_cons:        pros_cons = data.xpath('(//table/tbody)[1]/tr/td')    pros_cons_counter = 0    pros_cons_replace = ''    for value in pros_cons:                       if pros_cons_counter % 2 == 0:            pro = value.xpath('.//text()').string(multiple=True)            if pro:                review.add_property(type='pros', value=pro)                pros_cons_replace += pro        else:            con = value.xpath('.//text()').string(multiple=True)            if con:                review.add_property(type='cons', value=con)                pros_cons_replace += con        pros_cons_counter += 1    if not pros_cons:        pros = data.xpath('//p/strong[contains(text(), "Pros")]/parent::*/following-sibling::ul[1]/li')        for pro in pros:            pro = pro.xpath('.//text()').string(multiple=True)            review.add_property(type='pros', value=pro)            pros_cons_replace += pro        cons = data.xpath('//p/strong[contains(text(), "Cons")]/parent::*/following-sibling::ul[1]/li')        for con in cons:            con = con.xpath('.//text()').string(multiple=True)            review.add_property(type='cons', value=con)            pros_cons_replace += con    excerpt_json = simplejson.loads((data.xpath('(//script[@type="application/ld+json"])[position() = last()]/text()').string()))    excerpt = excerpt_json["articleBody"].replace('. ', '.').replace('.', '. ').replace('Conclusion ', '').replace(conclusion, '').replace(' ', ' ').replace(replace_content, '').strip()    if pros_cons_replace != '':        excerpt = excerpt.replace('Pros and Cons', '').replace('Pros', '').replace('Cons', '').replace(pros_cons_replace, '')        author = data.xpath('//span[@class="author vcard"]/a').first()    if author:        author_name = author.xpath('text()').string()        author_url = author.xpath('@href').string()        review.authors.append(Person(name=author_name, ssid=author_name, profile_url=author_url))    if excerpt:            review.add_property(type='excerpt', value=excerpt)            product.reviews.append(review)            session.emit(product)def process_reviews(data, context, session):    prods = data.xpath('//hr[@class="wp-block-separator is-style-wide"]/preceding-sibling::h3[1]')    if not prods:        prods = data.xpath('//table[contains(@class, "has-fixed-layout")]/preceding-sibling::h3[1]')       if len(prods) < 2:        prods = data.xpath('//h3[position() < last()]')    prods_check = data.xpath('(//hr[@class="wp-block-separator is-style-wide"]/preceding-sibling::h3)[1]/text()').string()    check = False    if prods_check == 'Pros:' or prods_check == 'Dimensions':        prods = data.xpath('(//hr[@class="wp-block-separator is-style-wide"]/preceding-sibling::h2)[position() < last() - 1]')                check = True    if context['url'] == X_URLS[1]:        prods = data.xpath('(//div[@class="wp-block-embed__wrapper"]/preceding-sibling::h2)[position() > 1]')    if context['url'] == X_URLS[2]:        prods = data.xpath('//h3[position() < last()]/preceding-sibling::h2')    if context['url'] == X_URLS[3]:        prods = data.xpath('//h3[(position() > 1 and position() < 7) or position() > 7]')    for prod in prods:        review = Review()        review.type = 'pro'        review.title = data.xpath('//h1[@class="entry-title"]//text()').string(multiple=True)        review.url = context['url']        review.date = data.xpath('//meta[@property="article:published_time"]/@content').string().split('T')[0]                conclusion = ""        conclusion_content = prod.xpath('(following-sibling::h4[contains(text(), "Final")])[1]/following-sibling::p')        if not conclusion_content:            conclusion_content = prod.xpath('(following-sibling::h4/span[contains(@id, "Final")])[1]/following::p')        for content in conclusion_content:            if content.xpath('strong/em') or content.xpath('em/strong') or 'If you’d like to learn more' in content.xpath('.//text()').string(multiple=True):                break            conclusion += content.xpath('.//text()').string(multiple=True)        if conclusion != "":            review.add_property(type='conclusion', value=conclusion)                excerpt = ""        excert_content = prod.xpath('following-sibling::p')                for content in excert_content:            if content.xpath('strong/em') or content.xpath('em/strong') or check is True and 'Interested? Check it out' in content.xpath('.//text()').string(multiple=True):                break            if 'Check price on Amazon' in content.xpath('.//text()').string(multiple=True):                excerpt += content.xpath('.//text()').string(multiple=True).replace('Check price on Amazon', '')                break            excerpt += content.xpath('.//text()').string(multiple=True)        excerpt_features = prod.xpath('(following-sibling::h4/span[contains(@id, "Features")])[1]/following::ul[1]//text()').string(multiple=True)        if not excerpt_features:            excerpt_features = prod.xpath('(following-sibling::h4[contains(text(), "Features")])[1]/following::ul[1]//text()').string(multiple=True)        if excerpt_features and excerpt_features not in excerpt:             excerpt += excerpt_features        excerpt = excerpt.replace('You may also be interested in:', '').replace('Final thoughts', '').replace('Final Thoughts', '').replace(conclusion, '')        pros_cons = prod.xpath('(following-sibling::table/tbody)[1]/tr/td')        pros_cons_counter = 0        for value in pros_cons:                           if pros_cons_counter % 2 == 0:                pro = value.xpath('.//text()').string(multiple=True)                if pro:                    review.add_property(type='pros', value=pro)            else:                con = value.xpath('.//text()').string(multiple=True)                if con:                    review.add_property(type='cons', value=con)            pros_cons_counter += 1        if not pros_cons:            pros = prod.xpath('(following-sibling::h3/span[contains(@id, "Pros")])[1]/parent::*/following-sibling::ul[1]/li')            for pro in pros:                pro = pro.xpath('text()').string()                review.add_property(type='pros', value=pro)            cons = prod.xpath('(following-sibling::h3/span[contains(@id, "Cons")])[1]/parent::*/following-sibling::ul[1]/li')            for con in cons:                con = con.xpath('text()').string()                review.add_property(type='cons', value=con)        author = data.xpath('//span[@class="author vcard"]/a').first()        if author:            author_name = author.xpath('text()').string()            author_url = author.xpath('@href').string()            review.authors.append(Person(name=author_name, ssid=author_name, profile_url=author_url))        product = Product()        product.url = prod.xpath('following-sibling::a[1]/@href').string()        if not product.url:            product.url = prod.xpath('(following-sibling::p//a[contains(@aria-label, "Amazon")])[1]/@href').string()        if not product.url:            product.url = context['url']        product.name = prod.xpath('.//text()').string(multiple=True).split('. ')[-1]        if 'What Mouse Do the Pros Use' in review.title:            product.name = prod.xpath('(following-sibling::p/strong)[1]/text()').string()        if product.name[0] == '#':            product.name = product.name[3:]        if product.name == 'Some benefits to having a keyboard with no number pad are:' or product.name == 'Keyboard sizes: a visual video':            continue        product.category = context['cat']        product.ssid = product.name.lower().replace(' – ', ' ').replace(' ', '-')        review.ssid = product.ssid        if excerpt != "":            review.add_property(type='excerpt', value=excerpt)            product.reviews.append(review)            session.emit(product)